mapper.select:
SELECT l.log_id, l.com_id, l.origin_dept_id, od.dept_name AS origin_dept_name, l.target_dept_id, td.dept_name AS target_dept_name, l.emp_id, e.emp_no, e.emp_name, l.ai_recommended, l.ai_reason, l.handover_snapshot, l.created_by, cb.emp_name AS created_by_name, l.created_at FROM dept_transfer_log l JOIN department od ON l.origin_dept_id = od.dept_id JOIN department td ON l.target_dept_id = td.dept_id JOIN employee e ON l.emp_id = e.emp_id JOIN employee cb ON l.created_by = cb.emp_id WHERE l.com_id = #{comId}
AND l.origin_dept_id = #{search.originDeptId}
AND l.target_dept_id = #{search.targetDeptId}
AND l.ai_recommended = #{search.aiRecommended}
AND l.created_at >= TO_DATE(#{search.dateFrom}, 'YYYY-MM-DD')
AND l.created_at < TO_DATE(#{search.dateTo}, 'YYYY-MM-DD') + 1
ORDER BY l.created_at DESC OFFSET #{search.pstartno} ROWS FETCH NEXT #{search.onepagelist} ROWS ONLY

SELECT COUNT(*)
FROM dept_transfer_log l
WHERE l.com_id = #{comId}

  AND l.origin_dept_id = #{search.originDeptId}


  AND l.target_dept_id = #{search.targetDeptId}


  AND l.ai_recommended = #{search.aiRecommended}


  AND l.created_at >= TO_DATE(#{search.dateFrom}, 'YYYY-MM-DD')


  AND l.created_at < TO_DATE(#{search.dateTo}, 'YYYY-MM-DD') + 1
